// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

interface IERC20 {
    function transfer(address to, uint256 amount) external returns (bool);
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
    function balanceOf(address account) external view returns (uint256);
    function totalSupply() external view returns (uint256);
    function approve(address spender, uint256 amount) external returns (bool);
}

// Simple ERC20 Token Contract
contract SimpleToken {
    string public name;
    string public symbol;
    uint8 public decimals = 18;
    uint256 public totalSupply;

    mapping(address => uint256) public balanceOf;
    mapping(address => mapping(address => uint256)) public allowance;

    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);

    constructor(string memory _name, string memory _symbol, uint256 _initialSupply, address _recipient) {
        name = _name;
        symbol = _symbol;
        totalSupply = _initialSupply * 10**decimals;
        balanceOf[_recipient] = totalSupply;
        emit Transfer(address(0), _recipient, totalSupply);
    }

    function transfer(address to, uint256 amount) external returns (bool) {
        require(balanceOf[msg.sender] >= amount, "Insufficient balance");
        balanceOf[msg.sender] -= amount;
        balanceOf[to] += amount;
        emit Transfer(msg.sender, to, amount);
        return true;
    }

    function transferFrom(address from, address to, uint256 amount) external returns (bool) {
        require(balanceOf[from] >= amount, "Insufficient balance");
        require(allowance[from][msg.sender] >= amount, "Insufficient allowance");

        balanceOf[from] -= amount;
        balanceOf[to] += amount;
        allowance[from][msg.sender] -= amount;

        emit Transfer(from, to, amount);
        return true;
    }

    function approve(address spender, uint256 amount) external returns (bool) {
        allowance[msg.sender][spender] = amount;
        emit Approval(msg.sender, spender, amount);
        return true;
    }
}

// Swap Contract that creates and manages its own tokens
contract SimpleSwapWithTokens {
    SimpleToken public tokenA;
    SimpleToken public tokenB;

    // 1:1 swap rate
    uint256 public constant SWAP_RATE = 1;

    // Pool initial liquidity amounts (in tokens, will be multiplied by 10**18)
    uint256 public constant INITIAL_LIQUIDITY_A = 10000; // 10,000 Token A
    uint256 public constant INITIAL_LIQUIDITY_B = 10000; // 10,000 Token B

    // Total supply for each token (in tokens, will be multiplied by 10**18)
    uint256 public constant TOTAL_SUPPLY_A = 1000000; // 1,000,000 Token A
    uint256 public constant TOTAL_SUPPLY_B = 1000000; // 1,000,000 Token B

    address public owner;
    uint256 public deploymentTime;

    event Swap(address indexed user, address indexed tokenIn, uint256 amountIn, uint256 amountOut);
    event TokensCreated(address tokenA, address tokenB, uint256 timestamp);
    event LiquidityAdded(uint256 amountA, uint256 amountB, uint256 timestamp);

    constructor() {
        owner = msg.sender;
        deploymentTime = block.timestamp;

        // Create Token A
        tokenA = new SimpleToken(
            "Swap Token A",
            "SWAPA", 
            TOTAL_SUPPLY_A,
            address(this)  // Mint all tokens to this contract initially
        );

        // Create Token B
        tokenB = new SimpleToken(
            "Swap Token B", 
            "SWAPB",
            TOTAL_SUPPLY_B,
            address(this)  // Mint all tokens to this contract initially
        );

        emit TokensCreated(address(tokenA), address(tokenB), deploymentTime);
        emit LiquidityAdded(
            INITIAL_LIQUIDITY_A * 10**18, 
            INITIAL_LIQUIDITY_B * 10**18, 
            deploymentTime
        );
    }

    // Swap tokenA for tokenB
    function swapAForB(uint256 amount) external {
        require(amount > 0, "Amount must be greater than 0");
        require(tokenB.balanceOf(address(this)) >= amount, "Insufficient tokenB in pool");

        // Transfer tokenA from user to contract
        require(tokenA.transferFrom(msg.sender, address(this), amount), "TokenA transfer failed");

        // Transfer tokenB from contract to user
        require(tokenB.transfer(msg.sender, amount), "TokenB transfer failed");

        emit Swap(msg.sender, address(tokenA), amount, amount);
    }

    // Swap tokenB for tokenA
    function swapBForA(uint256 amount) external {
        require(amount > 0, "Amount must be greater than 0");
        require(tokenA.balanceOf(address(this)) >= amount, "Insufficient tokenA in pool");

        // Transfer tokenB from user to contract
        require(tokenB.transferFrom(msg.sender, address(this), amount), "TokenB transfer failed");

        // Transfer tokenA from contract to user
        require(tokenA.transfer(msg.sender, amount), "TokenA transfer failed");

        emit Swap(msg.sender, address(tokenB), amount, amount);
    }

    // Owner can add more liquidity
    function addLiquidity(uint256 amountA, uint256 amountB) external {
        require(msg.sender == owner, "Only owner can add liquidity");
        require(amountA > 0 && amountB > 0, "Amounts must be greater than 0");

        // Transfer tokens from owner to contract
        require(tokenA.transferFrom(msg.sender, address(this), amountA), "TokenA transfer failed");
        require(tokenB.transferFrom(msg.sender, address(this), amountB), "TokenB transfer failed");

        emit LiquidityAdded(amountA, amountB, block.timestamp);
    }

    // Owner can distribute tokens to users (for testing/airdrops)
    function distributeTokens(address recipient, uint256 amountA, uint256 amountB) external {
        require(msg.sender == owner, "Only owner can distribute tokens");
        require(recipient != address(0), "Invalid recipient");
        require(amountA > 0 || amountB > 0, "At least one amount must be greater than 0");

        if (amountA > 0) {
            require(tokenA.transfer(recipient, amountA), "TokenA transfer failed");
        }

        if (amountB > 0) {
            require(tokenB.transfer(recipient, amountB), "TokenB transfer failed");
        }
    }

    // View functions
    function getTokenABalance() external view returns (uint256) {
        return tokenA.balanceOf(address(this));
    }

    function getTokenBBalance() external view returns (uint256) {
        return tokenB.balanceOf(address(this));
    }

    function getTokenAAddress() external view returns (address) {
        return address(tokenA);
    }

    function getTokenBAddress() external view returns (address) {
        return address(tokenB);
    }

    function getDeploymentInfo() external view returns (
        address _tokenA,
        address _tokenB,
        uint256 _deploymentTime,
        uint256 _poolBalanceA,
        uint256 _poolBalanceB
    ) {
        return (
            address(tokenA),
            address(tokenB),
            deploymentTime,
            tokenA.balanceOf(address(this)),
            tokenB.balanceOf(address(this))
        );
    }

    // Emergency functions (only owner)
    function emergencyWithdraw() external {
        require(msg.sender == owner, "Only owner can emergency withdraw");

        uint256 balanceA = tokenA.balanceOf(address(this));
        uint256 balanceB = tokenB.balanceOf(address(this));

        if (balanceA > 0) {
            tokenA.transfer(owner, balanceA);
        }

        if (balanceB > 0) {
            tokenB.transfer(owner, balanceB);
        }
    }
}
